mapper.select:
select

from user_group bug
inner join `org` bo on bug.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2
where bug.deleted = 0

    and bug.status = #{ew.status}


    and bug.code = #{ew.code}


    and bug.name like concat('%', #{ew.name}, '%')

and bo.id = #{ew.orgId}
order by bug.modified_time desc

select
,
from user_group bug inner join `org` bo on bug.org_id = bo.id and bo.deleted = 0 and bo.status = 1 and bo.audit_status = 2 where bug.deleted = 0 and bug.id = #{id}
